INSERT INTO jobs (job_name, industry, city, company_type, salary_min, salary_max, skills, soft_skills, is_fresh_friendly, friendly_level, jd_content, core_duties, education, major, experience, post_type, bonus_skills, salary_range, post_time, apply_deadline, jd_link, post_category, party_label) VALUES ('HRBP - 大连（实习）', '人力资源服务 / 咨询', '大连', '民营企业', 100, 120, '1. 熟练使用Office办公软件；2. 具备基础的招聘流程执行与培训协助能力', '1. 自律自觉，能在较强压力下工作；2. 良好的职业道德和职业操守，极强的责任感；3. 学习能力强，积极主动', 1, '友好', '1. 负责公司自有员工的招聘；2. 负责入职相关手续流程的协助；3. 负责基础知识的培训', '招聘全流程执行、简历筛选与面试、员工关系支持、OD 组织发展支持', '不限', '无强制专业限制', '可实习3个月，每周到岗3天，零基础可实习', '日常实习', '1. 有人力资源、猎头实习经验，及其他实习经验优先；2. 拥有学生会、社团组织、社会实践经验优先', '100-120元/天', '46111', '46131', 'https://www.shixiseng.com/intern/inn_jxagtufyc23z?pcm=pc_SearchList', 'HRBP类', '乙方（人力资源服务商 / 猎头 / 咨询公司）'), ('培训经理 - 菏泽（社招）', '互联网 / IT', '菏泽', '民营企业', 4000, 9000, '1. 精通培训需求分析、课程设计及效果评估等全流程操作；2. 熟练使用Office办公软件，可独立完成课件制作；3. 熟悉出行行业或互联网企业培训模式', '1. 具备优秀的沟通协调能力、演讲能力及项目推动力；2. 具备创新思维，学习能力强；3. 工作认真负责，目标导向', 0, '一般', '1. 搭建并优化公司培训体系，制定年度培训计划与预算；2. 组织开发通用类及专业类课程，建立内部讲师队伍；3. 统筹实施各类培训项目，监控培训过程并评估实施效果；4. 分析员工培训需求，针对性提升团队业务能力与综合素质', 'OD 组织发展支持', '大专及以上', '人力资源管理或相关专业', '1-3年，拥有多年培训管理经验', '社招（应届生可投）', '有人力资源管理师相关证书；有大型企业培训体系搭建经验', '4k-9k/月', '46112', NULL, 'BOSS直聘平台获取', 'OD类', '甲方（企业自有 HR 岗）'), ('培训经理 - 柳州（社招）', '快消', '柳州', '民营企业', 8000, 13000, '1. 可独立搭建培训体系、开发专项课程；2. 熟练使用Office办公软件，可完成课件、教材、视频等培训物料制作；3. 具备培训全流程落地与效果评估能力', '1. 具备良好的沟通能力与现场把控能力；2. 抗压性强，适应零售行业多店铺培训统筹节奏；3. 具备良好的团队协作精神', 0, '一般', '1. 培训体系搭建：基于公司需求，搭建管理和运营培训体系；2. 培训内容开发：联动市场部、货品部，开发针对性培训课程，设计标准化培训教材（如手册、课件、视频等），并根据需求持续优化课程内容；3. 培训实施与落地：根据各部门需求，统筹各类培训计划的落地、执行；针对市场部重点推广项目，开展专项培训与落地指导，保障活动执行效果；4. 培训效果评估：建立科学的培训效果评估体系，跟踪培训效果，形成培训评估报告，为培训体系优化提供数据支持；5. 培训团队管理：搭建内部培训师队伍，负责内部讲师的招募、培养与管理，提升内部讲师的授课能力；整合外部培训资源，根据需求可引入优质外部课程或讲师', 'OD 组织发展支持', '大专及以上', '工商管理、市场营销等相关专业', '3-5年，有鞋服零售行业、保险行业培训经验或主持相关经验优先', '社招（应届生可投）', '有鞋服零售/保险行业培训经验；有内部讲师队伍搭建与管理经验', '8k-13k/月', '46112', NULL, 'BOSS直聘平台获取', 'OD类', '甲方（企业自有 HR 岗）'), ('培训经理（无业绩管理岗） - 天津（社招）', '教育 / 培训', '天津', '民营企业', 10000, 14000, '1. 熟练运用PPT等办公软件，可独立完成课程开发与课件制作；2. 具备培训体系搭建、全流程落地与效果监控能力；3. 可独立开展各层级管理岗位能力提升培训', '1. 性格开朗，人品端正，积极上进，精益求精；2. 良好的职业素质及超强的责任心，抗压能力强；3. 富有团队合作精神及企业使命感，具备丰富的语言表达能力与引导力', 0, '一般', '1. 负责制定咨询团队培训发展计划，完成培训体系的搭建工作；2. 负责培训流程梳理、培训课程制定及培训内容开发管理工作；3. 每月定期开展线上线下培训工作；4. 负责推进咨询团队培训的有效实施与落地，监控培训进度及效果，并对培训后期工作进行统筹规划；5. 负责咨询团队入职培训及个人业务能力提升', 'OD 组织发展支持', '本科及以上', '专业不限', '5-10年，2年以上教育行业招生岗位工作经验', '社招（应届生可投）', '有教培行业校长/招生培训经验；有团队管理与培训体系搭建经验', '10k-14k/月', '46112', NULL, 'BOSS直聘平台获取', 'OD类', '甲方（企业自有 HR 岗）'), ('培训经理/主管 - 许昌（社招）', '互联网 / IT', '许昌', '民营企业', 10000, 15000, '1. 可独立完成培训需求调研、课程开发、培训实施与效果评估全流程；2. 熟练使用Office办公软件，可完成线上学习平台搭建与资源整合；3. 具备内部讲师团队与课程体系管理能力', '1. 具备良好的沟通协调和表达能力；2. 热爱培训工作，良好的抗压能力；3. 学习能力强，具备创新思维', 0, '一般', '1. 协助公司年度培训计划的制定和实施；2. 协助部门制定部门培训计划，并跟踪部门培训开展情况；3. 负责开展培训需求调研，跟踪培训项目的实施过程及培训效果，确保培训的有效性；4. 负责公司常规培训项目的开展实施，如新员工培训，公开课，早课，双导师等；5. 负责线上学习平台的搭建及资源的整合；6. 负责内部讲师团队及内部课程管理；7. 参与内部课程开发，培训项目设计，课程讲授，制度改善等工作', 'OD 组织发展支持', '大专及以上', '电子商务、人力资源、工商管理等相关专业优先', '3年以上培训工作经验', '社招（应届生可投）', '有电商行业培训经验；有内部课程开发与授课经验', '10k-15k/月', '46112', NULL, 'BOSS直聘平台获取', 'OD类', '甲方（企业自有 HR 岗）');